FormScriptItem.Script:
//ApproveSelfExclusion template function
//this function contains ajax call to node.js webservice called SelfExclusionApprove
var ProcessSelfExclusionApprove = function () {
  VV.Form.ShowLoadingPanel();
  //This gets all of the form fields.
  var formData = VV.Form.getFormDataCollection();

  var FormInfo = {};
  FormInfo.name = 'REVISIONID';
  FormInfo.value = VV.Form.DataID;
  formData.push(FormInfo);

  //Following will prepare the collection and send with call to server side script.
  var data = JSON.stringify(formData);
  var requestObject = $.ajax({
    type: "POST",
    url: VV.BaseAppUrl + 'api/v1/' + VV.CustomerAlias + '/' + VV.CustomerDatabaseAlias + '/scripts?name=GetSites',
    contentType: "application/json; charset=utf-8",
    data: data,
    success: '',
    error: ''
  });

  return requestObject;
};


VV.Form.ShowLoadingPanel();

var formValidationResults = VV.Form.Template.FormValidation();

if (formValidationResults === true) {
  $.when(
    ProcessSelfExclusionApprove()
  ).always(function (resp) {
    VV.Form.HideLoadingPanel();
    var messageData = '';
    if (typeof (resp.status) != 'undefined') {
      messageData = "A status code of " + resp.status + " returned from the server.  There is a communication problem with the  web servers.  If this continues, please contact the administrator and communicate to them this message and where it occured.";
      VV.Form.Global.DisplayMessaging(messageData);
    }
    else if (typeof (resp.statusCode) != 'undefined') {
      messageData = "A status code of " + resp.statusCode + " with a message of '" + resp.errorMessages[0].message + "' returned from the server.  This may mean that the servers to run the business logic are not available.";
      VV.Form.Global.DisplayMessaging(messageData);
    }
    else if (resp.meta.status == '200') {
      if (resp.data[0] != 'undefined') {
        if (resp.data[0] == 'Success') {
          messageData = 'Self-Exclusion is saved when the Yellow Banner appears above.';
          VV.Form.HideLoadingPanel();
          VV.Form.SetFieldValue('Status', 'Approved');
          VV.Form.SetFieldValue('VV Gambler ID', resp.data[2]);
          VV.Form.SetFieldValue('RelatedtoGambler', 'true');
          VV.Form.SetFieldValue('KPI Complete Date', Date());
          VV.Form.Template.CalculateKPI();
          VV.Form.Global.DisplayMessaging(messageData);
          VV.Form.DoPostbackSave();
        }
        else if (resp.data[0] == 'User Created') {
          messageData = 'Gambler was created, but the forms were not related. Please check the Admin Override checkbox and use the Relate to Gambler button below to manually relate the Self-Exclusion request to the Gambler Record. Self-Exclusion is saved when the Yellow Banner appears above.';
          VV.Form.HideLoadingPanel();
          VV.Form.SetFieldValue('VV Gambler ID', resp.data[2]);
          VV.Form.SetFieldValue('KPI Complete Date', Date());
          VV.Form.Template.CalculateKPI();
          VV.Form.Global.DisplayMessaging(messageData);
          VV.Form.DoPostbackSave();
        }
        else if (resp.data[0] == 'User Created, Email not sent') {
          messageData = 'Gambler created, but the email was not sent. Self-Exclusion is saved when the Yellow Banner appears above.';
          VV.Form.HideLoadingPanel();
          VV.Form.SetFieldValue('Status', 'Approved');
          VV.Form.SetFieldValue('VV Gambler ID', resp.data[2]);
          VV.Form.SetFieldValue('RelatedtoGambler', 'true');
          VV.Form.SetFieldValue('KPI Complete Date', Date());
          VV.Form.Template.CalculateKPI();
          VV.Form.Global.DisplayMessaging(messageData);
          VV.Form.DoPostbackSave();
        }
        else if (resp.data[0] == 'Error') {
          messageData = resp.data[1];
          VV.Form.HideLoadingPanel();
          VV.Form.Global.DisplayMessaging(messageData);
        }
        else {
          messageData = 'An unhandled response occurred from the unique record checking mechanism.  The form will not save at this time.  Please try again or communicate this issue to support.';
          VV.Form.HideLoadingPanel();
          VV.Form.Global.DisplayMessaging(messageData);
        }
      }
      else {
        messageData = 'The status of the response returned as undefined.';
        VV.Form.HideLoadingPanel();
        VV.Form.Global.DisplayMessaging(messageData);
      }
    }
    else {
      messageData = resp.data.error + '<br>';
      VV.Form.HideLoadingPanel();
      VV.Form.Global.DisplayMessaging(messageData);
    }
  });

}
else {
  VV.Form.HideLoadingPanel();
  VV.Form.Global.DisplayMessaging('All of the fields have not been filled in completely or there is an issue with the range of the data entered.  Highlight your mouse over the red icon to see how you can resolve the error stopping you from saving this form.')
}
